class Solution:
    def distinctSequences(self, n: int) -> int:
        MOD = 10**9 + 7
        @lru_cache(None)
        def dp(i, prev, prev_prev):
            if i == n:
                return 1
            res = 0
            for x in range(1, 7):
                if (x != prev or i - prev > 2) and (x != prev_prev or i - prev_prev > 2) and math.gcd(x, prev) == 1:
                    res += dp(i + 1, x, prev)
            return res % MOD
        return dp(0, -1, -1)
```
